import styles from "../styles.modules.scss";

export type DefaultSlideType = {
    type: "eventEntry" | null;
    id: string;
    background?: ImageSourceSets;
    ctas: InboxCTA[];
    displayTimer: boolean;
    isNew?: boolean;
    timerKind?: InboxEventTimerKind;
    timerLabel: string;
    timerTarget: number;
    title: string;
    countdown: number;
    hideTitle: boolean;
    limit?: number;
    targeting?: Targeting;
};

const DefaultSlideView = ({
    slide,
    countdown,
}: {
    slide: DefaultSlideType;
    countdown: number | undefined;
}) => {
    const {
        background,
        ctas,
        displayTimer,
        hideTitle,
        timerLabel,
        title,
        limit = 60,
        timerKind,
    } = slide;

    const sendCommand = useSendCommand();
    const openNewsArticle = useOpenNewsArticle();
    const {
        actions: { openModal },
    } = usePollContext();

    const handleClick = handleCTAClick(
        sendCommand,
        openNewsArticle,
        openModal,
        title,
    );

    const limitedTitle = title.substring(0, limit);

    const parsedCTAs = (() => {
        if (!timerKind) {
            return parseCTAs(ctas, handleClick);
        }

        if (timerKind === "SHOW_CTA") {
            return countdown && countdown > 0
                ? []
                : parseCTAs(ctas, handleClick);
        }

        if (timerKind === "HIDE_CTA") {
            return countdown && countdown > 0
                ? parseCTAs(ctas, handleClick)
                : [];
        }

        return parseCTAs(ctas, handleClick);
    })();
    const displayTimerFormatted = Boolean(
        displayTimer && countdown && countdown > 0,
    );

    return (
        <div className={`slide default ${styles.slide}`}>
            <div
                className={`content ${styles.content} ${
                    displayTimerFormatted ? "with-timer" : ""
                }`}
            >
                {background && (
                    <div className={`image ${styles.image}`}>
                        <Image sources={background} cover />
                    </div>
                )}

                {limitedTitle && !hideTitle && (
                    <>
                        <div className={`filter ${styles.filter}`} />

                        <div
                            className={`title ${styles.title}`}
                            data-title={limitedTitle}
                        >
                            {limitedTitle}
                        </div>
                    </>
                )}

                <div className={`wrapper ${styles.wrapper}`}>
                    {displayTimerFormatted && (
                        <div className={`timer ${styles.timer}`}>
                            <Timer
                                format="total-hours"
                                countdown={countdown}
                                timerLabel={timerLabel}
                            />
                        </div>
                    )}

                    {parsedCTAs.length ? (
                        <div
                            className={`ctas ${
                                parsedCTAs.length === 1 ? "single" : "multi"
                            } ${styles.ctas}`}
                        >
                            {parsedCTAs.map(
                                ({ label, onClick, variant }, index) => (
                                    <Button
                                        key={index}
                                        onClick={onClick}
                                        variant={variant}
                                    >
                                        <span className="buttonTextWrapper">
                                            {label || (
                                                <FormattedMessage id="globalText.langGo" />
                                            )}
                                        </span>
                                    </Button>
                                ),
                            )}
                        </div>
                    ) : null}
                </div>
            </div>
        </div>
    );
};

const mapTimerProperty = ({ timerTarget }: { timerTarget: number }) =>
    timerTarget;

export const withMappedTimerProperty = withCountdown(mapTimerProperty);

export const DefaultSlide = withMappedTimerProperty(DefaultSlideView);
import { useState } from "react";

export const useStateCountdown = (initialState) => useState(initialState);
import { useEffect } from "react";

export const useEffectStateUpdater = (frequency, target, updateCountdown) =>
    useEffect(() => {
        if (!target) return;

        const clear = () => {
            clearInterval(intervalId);
        };

        const intervalId = setInterval(() => {
            const millisecondsLeft = target - Date.now();

            if (millisecondsLeft < 1000) {
                updateCountdown(0);
                return clear();
            }

            updateCountdown(millisecondsLeft);
        }, frequency);

        return clear;
    }, []);
export function dispatchTabVisiblityEvent(visible: boolean) {
    const e = new CustomEvent("changeTabVisibility", {
        detail: {
            visible,
        },
    });
    window.dispatchEvent(e);
}

export type BackButtonBehavior = "news" | "back" | "close" | "esports";
/**
 * This allows us to control the behavior of the back button.
 * Whether it should work like the browser back button, take us back to the inbox main, or close the inbox
 *
 */
export function dispatchBackButtonConditionSetEvent(
    backButtonBehavior: BackButtonBehavior,
) {
    const e = new CustomEvent("backButtonConditionSet", {
        detail: {
            backButtonBehavior,
        },
    });
    window.dispatchEvent(e);
}

/*
 *
 * Sets the visibility of the back and home buttons
 */
export function dispatchControlButtonVisibilityEvent(visible: boolean) {
    const e = new CustomEvent("changeControlButtonVisibility", {
        detail: {
            visible,
        },
    });
    window.dispatchEvent(e);
}
import React from "react";
import ReactDOM from "react-dom";
import { Poll, PollCommonProps } from "../poll";
import { usePollContext } from "../../stores/poll";
import { usePollResults, useVoteWithAnalytics } from "../poll";
import { useSnowplowContext } from "../../analytics/snowplow";

import styles from "./styles.modules.scss";
import {
    dispatchTabVisiblityEvent,
    dispatchControlButtonVisibilityEvent,
} from "../../utils/event";

export const PollModal = ({
    isOpen,
    pollId,
    options,
    ...viewProps
}: PollCommonProps & {
    isOpen: boolean;
    onClose: () => void;
}) => {
    const {
        state: { voteCache, votingState, polls },
        canVote,
        isClosed,
        actions: { refreshPollInfo, voteFromModal: vote },
    } = usePollContext();
    const { optionsWithResults, showResults } = usePollResults(pollId, options);
    const { trackImpression } = useSnowplowContext();
    const voteWithAnalytics = useVoteWithAnalytics(pollId, options, vote);

    React.useEffect(() => {
        if (isOpen) {
            refreshPollInfo(pollId);
            dispatchTabVisiblityEvent(false);
            dispatchControlButtonVisibilityEvent(false);
            document.body.style.overflow = "hidden";
        } else {
            document.body.style.overflow = "initial";
            dispatchTabVisiblityEvent(true);
            dispatchControlButtonVisibilityEvent(true);
        }
    }, [isOpen]);

    React.useEffect(() => {
        if (isOpen) {
            // Poll impressions are have special prefix to distinguish them from the poll carousel impression
            trackImpression(`poll-${pollId}`, viewProps.pollTitle);
        }
    }, [pollId, isOpen]);

    if (!isOpen) {
        return null;
    }

    const modalRoot = document.getElementById("modal-root");

    if (!modalRoot) {
        return null;
    }

    const contents = (
        <Poll
            userVote={voteCache.votes[pollId] ?? null}
            canVote={canVote(pollId) && polls[pollId]?.status !== "closed"}
            isClosed={isClosed(pollId)}
            vote={voteWithAnalytics}
            options={optionsWithResults}
            showResults={showResults}
            isError={votingState === "fail"}
            isVoting={votingState === "voting"}
            extraClassNames={[String(styles.modal)]}
            {...viewProps}
        />
    );

    return ReactDOM.createPortal(contents, modalRoot);
};
