                                                : "milestone-unreached"
                                        }`}
                                        title={milestone.label}
                                    >
                                        {milestone.label}
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                    <div ref={bottomElementRef}></div>
                </div>
            </div>
            <div className={`wrapper ${styles.wrapper}`}>
                {ctas.length ? (
                    <div
                        className={`ctas ${
