export const EchoVaultSlide = ({
    pollSlide,
    trackerSlide,
}: {
    pollSlide: PollSlideType;
    trackerSlide: ProgressSlideType;
}) => {
    const scrollRef = useRef<HTMLDivElement>(null);
    const pollId = pollSlide.id;
    const options = pollSlide.options;
    const {
        state: { voteCache, votingState },
        canVote,
        isClosed,
        actions: { refreshPollInfo, vote, openModal },
    } = usePollContext();
    const { optionsWithResults, showResults } = usePollResults(pollId, options);
    const voteInPoll = (optionId: string[]) => vote(pollId, optionId);
    const voteWithAnalytics = useVoteWithAnalytics(pollId, options, voteInPoll);
    // Avoid showing the voted animation again when re-rendering
    const [votedNow, setVotedNow] = useState<boolean>(false);
    const scrollAnimationOver = useRef<boolean>(false);
    const [scrolledBeyondOriginal, setScrolledBeyondOriginal] =
        useState<boolean>(false);
    const [ref, isVisible] = useElementOnScreen<HTMLDivElement>({
        threshold: 0.001,
    });
    const { tracker, milestones, targeting, relatedMedia } = trackerSlide;
    const { title, relatedMedia: pollRelatedMedia } = pollSlide;

    const relatedMediaUrls = useMemo(
        () =>
            relatedMedia
                ?.map((media) => media.image?.url)
                .filter((image) => image !== undefined) || [],
        [relatedMedia],
    );

    const pollRelatedMediaLabels = useMemo(
        () =>
            pollRelatedMedia
                ?.map((media) => {
                    return { title: media.title, label: media.label };
                })
                .filter((label) => label !== undefined) || [],
        [pollRelatedMedia],
    );

    const lastOpenedDoorString =
        pollRelatedMediaLabels.find(({ title }) => title === "last-opened")
            ?.label ?? undefined;

    const lastOpenedDoor = lastOpenedDoorString
        ? Number(lastOpenedDoorString)
        : undefined;

    const lastOpenedDoorSeen =
        localStorage.getItem(
            `echo-vault-seen-door-open-${pollId}-${lastOpenedDoor}`,
        ) === "true";

    const openedDoors = pollRelatedMediaLabels
        .filter(({ title }) => title?.startsWith("opened-door-"))
        .map(({ title, label }) => {
            return {
                door: Number(title?.replace("opened-door-", "")),
                reward: label,
            };
        });

    const disabled =
        pollRelatedMediaLabels.find(({ title }) => title === "disabled")
            ?.label === "true" || false;

    const openedDoorsNumbers = openedDoors.map(({ door }) => door);

    const loaded = useImageLoader(relatedMediaUrls);

    const setupDoorStatuses = ({
        cache,
        pollId,
    }: {
        cache: typeof voteCache;
        pollId: string;
    }): Record<number, DoorData> => {
        if (cache.votes[pollId] !== undefined && cache.votes[pollId] !== null) {
            const votedId = cache.votes[pollId][0];

            const voted = pollSlide.options.find(
                (option) => option.id === votedId,
            );
            const votedDoor = voted?.title
                ? Number(voted.title.replace("door-", ""))
                : null;

            const disabledBaseObject: DoorData = {
                status: "disabled",
                votedNow: false,
            };

            const disabledBase: Record<number, DoorData> = {
                1: disabledBaseObject,
                2: disabledBaseObject,
                3: disabledBaseObject,
                4: disabledBaseObject,
                5: disabledBaseObject,
                6: disabledBaseObject,
                7: disabledBaseObject,
                8: disabledBaseObject,
                9: disabledBaseObject,
                10: disabledBaseObject,
                11: disabledBaseObject,
                12: disabledBaseObject,
                13: disabledBaseObject,
                14: disabledBaseObject,
                15: disabledBaseObject,
                16: disabledBaseObject,
                17: disabledBaseObject,
                18: disabledBaseObject,
                19: disabledBaseObject,
                20: disabledBaseObject,
            };

            if (!votedDoor) {
                return disabledBase;
            }

            if (votedDoor < 1 || votedDoor > 20) {
                return disabledBase;
            }

            if (!votedDoor && !isClosed(pollId) && !canVote(pollId)) {
                return disabledBase;
            }

            disabledBase[votedDoor] = {
                ...disabledBase[votedDoor],
                status: "voted",
                votedNow: votedNow,
            };

            for (let i = 1; i <= 20; i++) {
                if (openedDoorsNumbers.includes(i)) {
                    disabledBase[i] = {
                        status: "none",
                        votedNow: false,
                    };
                }
            }

            return disabledBase;
        }

        const noneBaseObject: DoorData = {
            status: "none",
            votedNow: false,
        };

        return {
            1: noneBaseObject,
            2: noneBaseObject,
            3: noneBaseObject,
            4: noneBaseObject,
            5: noneBaseObject,
            6: noneBaseObject,
            7: noneBaseObject,
            8: noneBaseObject,
            9: noneBaseObject,
            10: noneBaseObject,
            11: noneBaseObject,
            12: noneBaseObject,
            13: noneBaseObject,
            14: noneBaseObject,
            15: noneBaseObject,
            16: noneBaseObject,
            17: noneBaseObject,
            18: noneBaseObject,
            19: noneBaseObject,
            20: noneBaseObject,
        };
    };

    const [doorStatuses, setDoorStatuses] = useState<Record<number, DoorData>>(
        setupDoorStatuses({
            cache: voteCache,
            pollId,
        }),
    );

    useEffect(() => {
        refreshPollInfo(pollId);

        setDoorStatuses(
            setupDoorStatuses({
                cache: voteCache,
                pollId,
            }),
        );
    }, [voteCache, voteCache.avatarId, pollId]);

    const toggleDoor = (doorNumber: number) => {
        if (openedDoorsNumbers.includes(doorNumber)) {
            const openDoor = openedDoors.find(
                (openedDoor) => openedDoor.door === doorNumber,
            );

            const reward = openDoor?.reward;
            if (reward) {
                if (reward === "removeMortis") {
                    return;
                }

                if (reward === "oniKenjiMangaChroma") {
                    const oniKenjiCode =
                        pollRelatedMediaLabels.find(
                            ({ title }) => title === "oni-kenji-code",
                        )?.label ?? undefined;

                    if (!oniKenjiCode) return;

                    claimOniKenjiCode(oniKenjiCode);
                } else {
                    (async () => {
                        (await bridge()).openShop();
                    })();
                }
            }
        }

        setDoorStatuses((prev) => {
            const newStatuses: Record<number, DoorData> = {};
            for (let i = 1; i <= 20; i++) {
                if (i === doorNumber) {
                    newStatuses[i] = {
                        status:
                            prev[i]?.status === "none" &&
                            !openedDoorsNumbers.includes(i)
                                ? "selected"
                                : "none",
                        votedNow: false,
                    };
                } else {
                    newStatuses[i] = {
                        status: "none",
                        votedNow: false,
                    };
                }
            }
            return newStatuses;
        });
    };

    const handleVote = async (doorNumber: number) => {
        const option = options.find(
            (option) => option.title === `door-${doorNumber}`,
        );

        if (option) {
            try {
                await voteWithAnalytics([option.id]);
                refreshPollInfo(pollId);

                if (votingState === "fail") return;

                setVotedNow(true);

                setDoorStatuses(
                    setupDoorStatuses({
                        cache: voteCache,
                        pollId,
                    }),
                );
            } catch (e) {
                console.error("Error voting for door", e);
            }
        }
    };

    useEffect(() => {
        if (!loaded) return;

        const handleScrollEnd = () => {
            if (!scrollRef.current) return;

            const sectionWidth = scrollRef.current.scrollWidth / 3;
            const scrollLeft = scrollRef.current.scrollLeft;

            const sectionRatio = scrollLeft / sectionWidth;
            const currentSection =
                sectionRatio <= 1 ? 1 : Math.ceil(sectionRatio);

            if (currentSection < 2) {
                const newScrollLeft =
                    sectionWidth * 2 + (scrollLeft - sectionWidth);

                scrollRef.current.scrollLeft = newScrollLeft;
            } else if (currentSection > 2) {
                const newScrollLeft =
                    sectionWidth + (scrollLeft - sectionWidth * 2);

                scrollRef.current.scrollLeft = newScrollLeft;
            }
        };

        const handleScroll = () => {
            if (!scrollRef.current) return;
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            clearTimeout((scrollRef.current as any)._scrollEndTimer);
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            (scrollRef.current as any)._scrollEndTimer = setTimeout(() => {
                handleScrollEnd();
            }, 100);

            const sectionWidth = scrollRef.current.scrollWidth / 3;
            const scrollLeft = scrollRef.current.scrollLeft;

            if (
                scrollAnimationOver.current &&
                scrollLeft > sectionWidth &&
                scrollLeft < sectionWidth * 2
            ) {
                setScrolledBeyondOriginal(true);
            }
        };

        setTimeout(() => {
            if (scrollRef.current) {
                const scrollWidth = scrollRef.current.scrollWidth;
                const sectionWidth = scrollWidth / 3;

                // Get random number between 1 and 20, which is not in the openedDoorNumbers array
                const randomStartingDoor = ((): number => {
                    const availableDoors = Array.from(
                        { length: 20 },
                        (_, i) => i + 1,
                    ).filter((door) => !openedDoorsNumbers.includes(door));
                    const randomIndex = Math.floor(
                        Math.random() * availableDoors.length,
                    );

                    return availableDoors[randomIndex] || 1;
                })();

                const startingPoint =
                    sectionWidth +
                    (sectionWidth / 20) * (randomStartingDoor - 2);

                const scrollLead = 500;

                if (lastOpenedDoor !== undefined && !lastOpenedDoorSeen) {
                    const rewardStartingPoint = getClosestDoorScrollToPosition(
                        sectionWidth +
                            (sectionWidth / 20) * (lastOpenedDoor - 2),
                        scrollWidth,
                    );

                    const animationStartingPoint =
                        rewardStartingPoint < scrollLead
                            ? 0
                            : rewardStartingPoint - scrollLead;

                    scrollToDoor({
                        scrollRef,
                        startingPoint: animationStartingPoint,
                        targetPoint: rewardStartingPoint,
                    });

                    setTimeout(() => {
                        scrollAnimationOver.current = true;
                    }, 1200);

                    localStorage.setItem(
                        `echo-vault-seen-door-open-${pollId}-${lastOpenedDoor}`,
                        "true",
                    );
                } else {
                    const fixedStartingPoint = getClosestDoorScrollToPosition(
                        startingPoint,
                        scrollWidth,
                    );

                    const animationStartingPoint =
                        fixedStartingPoint < scrollLead
                            ? 0
                            : fixedStartingPoint - scrollLead;

                    scrollToDoor({
                        scrollRef,
                        startingPoint: animationStartingPoint,
                        targetPoint: fixedStartingPoint,
                    });

                    setTimeout(() => {
                        scrollAnimationOver.current = true;
                    }, 1200);
                }
            }
        }, 150);

        scrollRef.current?.addEventListener("scroll", handleScroll);

        return () => {
            scrollRef.current?.removeEventListener("scroll", handleScroll);
        };
    }, [loaded]);

    const [decor5Animations] = useState(
        Array.from({ length: 20 }, () => {
            const randomSpeed = (Math.random() * (2.5 - 1.5) + 1.5) * 1.5;

            const p1 = (Math.random() * (0.7 - 0.3) + 0.3).toFixed(2);
            const p2 = (Math.random() * (0.7 - 0.3) + 0.3).toFixed(2);
            const randomCubicBezier = `cubic-bezier(${p1}, 0, ${p2}, 1)`;

            return {
                randomSpeed,
                randomCubicBezier,
            };
