            "door-2": "--door-2",
            "door-2-open": "--door-2-open",
            "door-3": "--door-3",
            "door-3-open": "--door-3-open",
            "door-4": "--door-4",
            "door-4-open": "--door-4-open",
            "door-5": "--door-5",
            "door-5-open": "--door-5-open",
            "door-6": "--door-6",
            "door-6-open": "--door-6-open",
            "door-7": "--door-7",
            "door-7-open": "--door-7-open",
            "door-8": "--door-8",
            "door-8-open": "--door-8-open",
            "door-9": "--door-9",
            "door-9-open": "--door-9-open",
            "door-10": "--door-10",
            "door-10-open": "--door-10-open",
            "door-11": "--door-11",
            "door-11-open": "--door-11-open",
            "door-12": "--door-12",
            "door-12-open": "--door-12-open",
            "door-13": "--door-13",
            "door-13-open": "--door-13-open",
            "door-14": "--door-14",
            "door-14-open": "--door-14-open",
            "door-15": "--door-15",
            "door-15-open": "--door-15-open",
            "door-16": "--door-16",
            "door-16-open": "--door-16-open",
            "door-17": "--door-17",
            "door-17-open": "--door-17-open",
            "door-18": "--door-18",
            "door-18-open": "--door-18-open",
            "door-19": "--door-19",
            "door-19-open": "--door-19-open",
            "door-20": "--door-20",
            "door-20-open": "--door-20-open",
            "decor-1": "--decor-1",
            "decor-2": "--decor-2",
            "decor-3": "--decor-3",
            "decor-4": "--decor-4",
            "decor-5": "--decor-5",
            "decor-5-glow": "--decor-5-glow",
            "bg-1": "--bg-1",
            "bg-2": "--bg-2",
