            "reward-coin": "--reward-coin",
            "reward-coins200": "--reward-coins200",
            "reward-coins1000": "--reward-coins1000",
            "reward-credits500": "--reward-credits500",
            "reward-gem": "--reward-gem",
            "reward-gems20": "--reward-gems20",
            "reward-hyperchargeStarrDrop": "--reward-hyperchargeStarrDrop",
            "reward-removeMortis": "--reward-removeMortis",
            "reward-lumi": "--reward-lumi",
            "reward-megaboxes2": "--reward-megaboxes2",
            "reward-oniKenjiMangaChroma": "--reward-oniKenjiMangaChroma",
            "reward-powerPoints200": "--reward-powerPoints200",
            "reward-powerPoints500": "--reward-powerPoints500",
            "reward-powerPoints1000": "--reward-powerPoints1000",
            "reward-pumpkinBoxes3": "--reward-pumpkinBoxes3",
            "reward-randomStarrDrop": "--reward-randomStarrDrop",
            "reward-randomStarrDrops10": "--reward-randomStarrDrops10",
            "reward-sprayBoo": "--reward-sprayBoo",
            "reward-sushiRolls10": "--reward-sushiRolls10",
            "reward-ultraTrophyBox": "--reward-ultraTrophyBox",
        };

        Object.entries(imageMap).forEach(([title, cssVar]) => {
            const imageUrl = findRelatedMediaByTitle(relatedMedia ?? [], title);
            if (imageUrl) styles[cssVar] = `url("${imageUrl}")`;
        });

        return styles;
    }, [relatedMedia]);

    const ctas = parseCTAs(trackerSlide.ctas, handleClick);

