        <>
            <div
                className={`slide progress-indicator ${styles.slide} ${
                    isVisible ? "visible" : ""
                } ${hasMileStoneLabels ? "with-milestone-labels" : ""} ${
                    targeting?.campaignId ?? ""
                } without-title ${trackerSlide.lang}`}
                ref={ref}
                style={barStyle}
            >
                <div className={`loader ${loaded ? "loaded" : ""}`}></div>
                <GesturingHand
                    shouldHide={scrolledBeyondOriginal}
                    lower={oniKenjiCode !== undefined}
                />
                {votingState === "fail" && (
                    <div className="error">
                        <FormattedMessage id="globalText.langVoteTryAgainLabel" />
                    </div>
                )}
                <div className="walls swiper-no-swiping" ref={scrollRef}>
                    <div className="wall">
                        <WallSet
                            num={1}
                            key="wall-set-1"
                            scrollRef={scrollRef}
                            doorStatuses={doorStatuses}
                            toggleDoor={toggleDoor}
                            handleVote={handleVote}
                            showResults={showResults}
                            optionsWithResults={optionsWithResults}
                            votingState={votingState}
                            decor5Animations={decor5Animations}
                            openedDoors={openedDoors}
                            disabled={disabled}
                        />
                        <WallSet
                            num={2}
                            key="wall-set-2"
                            scrollRef={scrollRef}
                            doorStatuses={doorStatuses}
                            toggleDoor={toggleDoor}
                            handleVote={handleVote}
                            showResults={showResults}
                            optionsWithResults={optionsWithResults}
                            votingState={votingState}
                            decor5Animations={decor5Animations}
                            openedDoors={openedDoors}
                            disabled={disabled}
                        />
                        <WallSet
                            num={3}
                            key="wall-set-3"
                            scrollRef={scrollRef}
                            doorStatuses={doorStatuses}
                            toggleDoor={toggleDoor}
                            handleVote={handleVote}
                            showResults={showResults}
                            optionsWithResults={optionsWithResults}
                            votingState={votingState}
                            decor5Animations={decor5Animations}
                            openedDoors={openedDoors}
                            disabled={disabled}
                        />
                    </div>
                </div>
                <div className="floor"></div>
                <Front scrollRef={scrollRef} />
                {timerString !== undefined && (
                    <Timer
                        timerString={timerString}
                        lang={String(trackerSlide.lang)}
                    />
                )}
                <div className={`content ${styles.content}`}>
                    {title && (
                        <>
                            <div className={`filter ${styles.filter}`} />
                            <div className="titles">
                                <div
                                    className={`title ${styles.title} `}
                                    data-title={title}
                                >
                                    {title}
                                </div>
                                <div className="subtitle">
                                    <FormattedMessage id="globalText.langEchoVaultInstructionTemporary" />
                                </div>
                            </div>
                        </>
                    )}
                    <div className={`trackers ${styles.trackers}`}>
                        {isVisible && (
                            <>
                                <div className="tracker-dice-wrapper">
                                    <div className={`tracker-wrapper`}>
                                        <div
                                            className={`tracker ${styles.tracker} ${tracker.progress === 100 ? "full" : ""}`}
                                        >
                                            <div
                                                style={style}
                                                className={`tracker-progress ${
                                                    styles["tracker-progress"]
                                                } ${
                                                    fillPercentage > 99
                                                        ? "almost-complete"
                                                        : ""
                                                }`}
                                                ref={trackerProgressRef}
                                            >
                                                <RawValue
                                                    tracker={tracker}
                                                    trackerProgressRef={
                                                        trackerProgressRef
                                                    }
                                                />
                                            </div>
                                        </div>
                                        <div
                                            className={`icon-container ${styles["icon-container"]}`}
                                            style={style}
                                        >
                                            <div
                                                className={`icon ${styles.icon}`}
                                            ></div>
                                        </div>
                                    </div>
                                </div>
                            </>
                        )}

                        <div
                            className={`milestone-label-wrapper ${styles["milestone-label-wrapper"]}`}
                        >
                            {milestones.map((milestone, index) => {
                                if (!milestone.label) {
                                    return <div key={index} />;
                                }

                                const milestonePosition = Math.max(
                                    milestone.progress,
                                    5, // 5% is the minimum we support without the UI looking totally wack
                                );

                                const hasReachedMilestone = milestone.unlocked;

                                const style = {
                                    left: `${milestonePosition}%`,
                                };

                                return (
                                    <div
                                        key={index}
                                        style={style}
                                        className={`milestone-label ${
                                            styles["milestone-label"]
                                        } ${
                                            hasReachedMilestone
                                                ? styles["milestone-reached"]
                                                : styles["milestone-unreached"]
                                        } ${
                                            hasReachedMilestone
                                                ? "milestone-reached"
                                                : "milestone-unreached"
                                        }`}
                                        title={milestone.label}
                                    >
                                        {milestone.label}
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                    <div ref={bottomElementRef}></div>
                </div>
                <div className={`wrapper ${styles.wrapper}`}>
                    {ctas.length ? (
                        <div
                            className={`ctas ${
                                ctas.length === 1 ? "single" : "multi"
                            } ${styles.ctas}`}
                        >
                            {ctas.map(({ label, variant, onClick }, index) => {
                                return (
                                    <Button
                                        key={index}
                                        onClick={onClick}
                                        variant={variant}
                                        size="sm"
                                    >
                                        <span className="buttonTextWrapper">
                                            {label || (
                                                <FormattedMessage id="globalText.langGo" />
                                            )}
                                        </span>
                                    </Button>
                                );
                            })}
                        </div>
                    ) : null}
                </div>
                {oniKenjiCode !== undefined && (
                    <div className="oniKenjiButton">
                        <Button
                            onClick={() => {
                                claimOniKenjiCode(oniKenjiCode);
                            }}
                            variant="green"
                            size="sm"
                        >
                            <span className="buttonTextWrapper">
                                <FormattedMessage id="globalText.langEchoVaultClaimTemporary" />
                            </span>
                        </Button>
                    </div>
                )}
            </div>
        </>
    );
};

