function WallPart({
    doorNumber,
    onToggle,
    onVote,
    data,
    result,
    votingState,
    reward,
    disabled,
}: {
    doorNumber: number;
    onToggle: () => void;
    onVote: () => void;
    data?: DoorData;
    result?: number;
    votingState: ReturnType<typeof usePollContext>["state"]["votingState"];
    reward?: string;
    disabled: boolean;
}) {
    return (
        <div
            className={`wall-part ${disabled ? "disabled" : data?.status} ${reward ? "opened" : ""} ${data?.votedNow ? "voted-now" : ""}`}
        >
            {data?.votedNow === true && (
                <div className="voted-overlay">
                    <div className="voted-icon"></div>
                    <div className="voted-text">
                        <FormattedMessage id="globalText.langVoted" />
                    </div>
                </div>
            )}
            {(data?.status === "voted" || data?.status === "disabled") &&
                result !== undefined && (
                    <div
                        className={`result-overlay ${data?.votedNow ? "voted-now" : ""}`}
                    >
                        <div className="result-text">
                            {(Math.round(result * 1000) / 10).toFixed(1)}%
                        </div>
                        <div className="result-shadows"></div>
                        <div className="result-border"></div>
                    </div>
                )}
            <div className="button-wrapper">
                <Button
                    onClick={() => {
                        onVote();
                    }}
                    variant="green"
                    disabled={votingState === "voting"}
                >
                    <span className="buttonTextWrapper">
                        <FormattedMessage id="globalText.langVoteDefaultButtonLabel" />
                    </span>
                </Button>
            </div>
            {reward !== undefined && (
                <div
                    className={`reward reward-${reward} reward-door-${doorNumber}`}
                >
                    <div className="icon"></div>
                </div>
            )}
            <div
                className={`door door-${doorNumber} ${reward ? "opened" : ""}`}
                onClick={() => {
                    if (data?.status === "none") {
                        onToggle();
                    } else if (data?.status === "selected") {
                        onToggle();
                    }
                }}
            ></div>
            <div className="shadow"></div>
        </div>
    );
}

function Window({
    scrollRef,
    setNum,
    count,
}: {
    scrollRef: React.RefObject<HTMLDivElement>;
    setNum: number;
    count: number;
}) {
    const windowScrollRef = useRef<HTMLDivElement>(null);
    const [scrollPos, setScrollPos] = useState<number>(0);

    useEffect(() => {
        const handleScroll = () => {
            if (!scrollRef.current) return;

            const scrollLeft = scrollRef.current.scrollLeft;
            const scrollWidth = scrollRef.current.scrollWidth;

            // setNum is the part of the section of windows, there are a total of 3
            // count is the number of the window in that section, from 1 to 5

            // Each section is scrollWidth / 3 wide
            // Each window (count) in the section should have its own ratio from 0 to 1
            const sectionStart = (scrollWidth / 3) * (setNum - 1);
            const sectionWidth = scrollWidth / 3;
            const windowWidth = sectionWidth / 5; // 5 windows per section

            const windowStart = sectionStart + windowWidth * (count - 2);
            const windowEnd = windowStart + windowWidth;

            // Clamp scrollLeft to window's range
            const clampedScrollLeft = Math.max(
                Math.min(scrollLeft, windowEnd),
                windowStart,
            );

            // Ratio from 0 to 1 for this window
            const partScrollRatio =
                (clampedScrollLeft - windowStart) / windowWidth;

            setScrollPos(-13.5 * partScrollRatio);
        };

        scrollRef.current?.addEventListener("scroll", handleScroll);

        return () => {
            scrollRef.current?.removeEventListener("scroll", handleScroll);
        };
    }, [scrollRef]);

    return (
        <div className="window-wrapper">
            <div className={`frame ${count % 2 ? "type-1" : "type-2"}`}></div>
            <div className="window" ref={windowScrollRef}>
                <div
                    className={`background window-${count}`}
                    style={{
                        transform: `translateX(${scrollPos}%)`,
                    }}
                ></div>
            </div>
