function getClosestDoorScrollToPosition(
    scrollLeft: number,
    scrollWidth: number,
) {
    const breakPoints = scrollWidth / 60;

    let closest = breakPoints;
    for (let i = 1; i < 60; i++) {
        const point = breakPoints * i;
        if (Math.abs(point - scrollLeft) < Math.abs(closest - scrollLeft)) {
            closest = point;
        }
    }

    return closest;
}

function smoothScroll({
    scrollRef,
    startingPoint,
    targetPoint,
    duration,
}: {
    scrollRef: React.RefObject<HTMLDivElement>;
    startingPoint: number;
    targetPoint: number;
    duration: number;
}) {
    const change = targetPoint - startingPoint;
    const startTime = performance.now();

    function animateScroll(currentTime: number) {
        const elapsed = currentTime - startTime;
        const progress = Math.min(elapsed / duration, 1);
        // Ease in-out cubic
        const ease =
            progress < 0.5
                ? 4 * progress * progress * progress
                : 1 - Math.pow(-2 * progress + 2, 3) / 2;

        if (!scrollRef.current) return;

        scrollRef.current.scrollLeft = startingPoint + change * ease;

        if (elapsed < duration) {
            requestAnimationFrame(animateScroll);
        }
    }

    requestAnimationFrame(animateScroll);
}

function useImageLoader(urls: string[]) {
    const [imageLoadCount, setImageLoadCount] = useState(0);
    const [imageUrls, setImageUrls] = useState<string[]>();

    useEffect(() => {
        setImageLoadCount(0);
        setImageUrls(urls);
    }, [urls]);

    useEffect(() => {
        if (!imageUrls) return;
        imageUrls.forEach((url) => {
            const image = new Image();
            image.src = url;
            image.onload = () => {
                setImageLoadCount((count) => count + 1);
            };
            image.onerror = () => {
                setImageLoadCount((count) => count + 1);
            };
        });
    }, [imageUrls]);

    const loaded = imageLoadCount === imageUrls?.length;

    return loaded;
}

