function FullscreenEntryCarouselSlide(slide: InboxFullscreenEntrySlide) {
    const isPortrait = window.innerWidth < window.innerHeight;

    const [isFullHeight, setIsFullheight] = useState(false);

    const onClick = (e: React.MouseEvent<HTMLElement>) => {
        const el = e.target as HTMLElement;

        if (el.tagName === "A") {
            return;
        }

        if (isFullHeight) {
            return;
        }

        if (!isPortrait) {
            return;
        }

        setIsFullheight(!isFullHeight);
    };

    const style = isPortrait
        ? {
              maxHeight: isFullHeight ? "80vh" : "30vh",
          }
        : {};

    return (
        <div className={styles.slide}>
            {slide.backgroundMedia && <Image sources={slide.backgroundMedia} />}

            {slide.body && (
                <div
                    className={`${styles.prompt} prompt`}
                    onClick={onClick}
                    style={style}
                >
                    <Html html={slide.body} />
                </div>
            )}
        </div>
    );
}

function FullscreenEntryCarousel(props: {
    entry: InboxFullscreenEntry;
    locale: { lang: string };
    closeEntry: (entryId: string) => void;
}) {
    const { entry, closeEntry, locale } = props;

    const sendCommand = useSendCommand();
    const openNewsArticle = useOpenNewsArticle();

    const onLinkClick = (cta: Cta) => {
        if (cta.urlType === "article") {
            const page =
                entry.type === "esportFullscreenCarousel" ? "esport" : "news";

            openNewsArticle(cta.url.id, "", page);

            closeEntry(entry.id);
            return;
        }
        if (cta.urlType === "bridgeFunction") {
            sendCommand(BRIDGE_FUNCTION, {
                functionName: cta.functionName,
                functionArgs: cta.functionArgs,
            });
            return;
        }

        sendCommand(OPEN_LINK, {
            url: cta.url,
            id: cta.id,
            label: cta.label,
        });
        closeEntry(entry.id);
    };

    const cta = entry.readMoreButton;

    return (
        <div className={`${styles.carousel} fullscreen-carousel`}>
            <div className={`${styles.buttons} buttons`}>
                {cta && (
                    <Button
                        variant={cta.variant}
                        onClick={() => onLinkClick(cta)}
