    const closeEntry = (entryId: string) => {
        actions.closeFullscreenEntry(entryId);
        setHasShownOneEntryThisSession(true);
    };

    const activeEntry = entries.find(
        (entry) => entry.id === state.activeEntryId,
    );

    useEffect(() => {
        if (activeEntry) {
            // This is an ugly hack to prevent the poll modal from resetting this state... Will be fixed in the future
            setTimeout(() => {
                document.body.style.overflow = "hidden";
            }, 50);
        } else {
            document.body.style.overflow = "initial";
        }
    }, [activeEntry]);

    useEffect(() => {
        if (state.activeEntryId) {
            trackImpression(
                state.activeEntryId,
                `Fullscreen Entry - ${state.activeEntryId}`,
            );
        }
    }, [state.activeEntryId]);

    const modalRootEl = document.getElementById("modal-root");

    if (!modalRootEl) {
        return null;
    }

    if (hasShownOneEntryThisSession) {
        return null;
    }

    if (!activeEntry) {
        return null;
    }

    const contents = (
        <div
            className={`${styles.fullscreen} fullscreen-entry ${tab ?? ""}`}
            {...viewProps}
        >
            <FullscreenEntryCarousel
                closeEntry={closeEntry}
                entry={activeEntry}
                locale={locale}
            />
        </div>
    );

    return ReactDOM.createPortal(contents, modalRootEl);
};

export function FullscreenEntryContainer(
    props: FullscreenEntryContainerProps,
): ReactElement {
    const entryIds = props.entries.map((entry) => entry.id);

    return (
        <FullscreenEntryContextProvider availableEntryIds={entryIds}>
            <FullscreenEntryModal tab={props.tab} entries={props.entries} />

            {props.children}
        </FullscreenEntryContextProvider>
    );
}
